text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과를 전제로 금요일 15:00 KST를 공개 릴리스 목표로 둔다.",
        "basis": "수요일 제안 이후 Doyun의 이의 제기가 있었고, 최종 결정이 금요일 15:00 KST로 정리됨."
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "basis": "smoke-theme-pack.mjs에서 mismatch를 무시하자는 제안은 기각됨."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일에 공개 릴리스한다.",
        "result": "기각",
        "reason": "스모크 테스트 선통과가 필요하다는 이의가 제기되었고, 최종 공개 목표는 금요일 15:00 KST로 정리됨."
      },
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
        "result": "기각",
        "reason": "mismatch 발생 시 먼저 패키지 설정을 확인하기로 결정했기 때문."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 골",
        "note": "확정된 공개 릴리스 일정이 아니라 내부 목표 수준으로만 언급됨."
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 언급은 있었으나 확정 소유자 배정은 없었음."
      }
    ],
    "risks": [
      {
        "risk": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있음."
      },
      {
        "risk": "README 설치 절차가 오래된 상태라면 릴리스 노트가 사용자에게 오해를 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 골을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 점검한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미배정",
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "미확정",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이전/직후에 Minjun의 스모크 테스트 결과가 공유되었는지 확인",
      "스모크 테스트 통과 여부에 따라 금요일 15:00 KST 공개 릴리스 목표 유지 가능 여부 확인",
      "스모크 결과 공유 후 Hara의 tarball 경로 점검 결과 확인",
      "Doyun의 failure triage note가 금요일 12:00 KST까지 action_items.md에 반영되었는지 확인",
      "README 설치 절차 검토 담당자 배정 필요 여부 확인",
      "최종 릴리스 승인 권한자와 릴리스 노트 내 수요일 스트레치 골 언급 여부를 후속 의사결정 항목으로 유지"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 관련 사실",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "배정되지 않은 owner",
      "명시되지 않은 deadline",
      "결정되지 않은 승인 권한자",
      "확정되지 않은 README 검토 책임자"
    ]
  },
  "non_invention_rules": [
    "인라인 합성 회의 메모에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "명시적으로 확정되지 않은 owner나 due date를 확정 사실처럼 쓰지 않는다.",
    "수요일 일정은 공개 릴리스 확정안이 아니라 내부 스트레치 골로만 기록한다.",
    "기각된 제안과 확정된 결정은 반드시 분리해서 기록한다.",
    "open question은 답이 정해지지 않은 상태로 유지하고 추정으로 메우지 않는다."
  ]
}
